public class MoleMovement : MonoBehaviour
{
    [Header("Bewegungseinstellungen")]
    [SerializeField] private float distance = 0.5f; // Wie weit der Wurm sich bewegt
    [SerializeField] private float speed = 1.5f; // Geschwindigkeit des Wurms

    [Header("Zeiteinstellungen")]
    [SerializeField] private float minWarteZeitUnten = 1f; // Minimale Zeit unten
    [SerializeField] private float maxWarteZeitUnten = 3f; // Maximale Zeit unten
    [SerializeField] private float minWarteZeitOben = 0.5f; // Minimale Zeit oben
    [SerializeField] private float maxWarteZeitOben = 2f; // Maximale Zeit oben

    [Header("Treffer-Einstellungen")]
    [Tooltip("Tag des Hammers (muss am Hammer-Objekt gesetzt sein)")]
    [SerializeField] private string hammerTag = "Hammer";
    [Tooltip("Wie schnell der Wurm nach einem Treffer nach unten geht")]
    [SerializeField] private float hitSpeed = 4f;

    [Header("Gleichzeitige Würmer begrenzen")]
    [Tooltip("Wie viele Würmer gleichzeitig maximal oben sein dürfen (0 = unbegrenzt)")]
    public static int maxMolesUp = 2; // Wird vom MoleSpawner gesetzt

    // Zählt wie viele Würmer gerade oben sind (alle Instanzen teilen diesen Wert)
    private static int currentMolesUp = 0;

    private Vector3 startPosition;
    private Vector3 zielPosition;
    private float timer;
    private bool isUp = false;
    private bool isMoving = false;
    private bool isHit = false;

    /// <summary>
    /// Wird vom MoleSpawner aufgerufen, um die Einstellungen zu setzen (vor Start).
    /// </summary>
    public void SetSettings(float dist, float spd, float minDown, float maxDown, float minUp, float maxUp)
    {
        distance          = dist;
        speed             = spd;
        minWarteZeitUnten = minDown;
        maxWarteZeitUnten = maxDown;
        minWarteZeitOben  = minUp;
        maxWarteZeitOben  = maxUp;
    }

    void Start()
    {
        // Startposition speichern
        startPosition = transform.localPosition;
        // Zielposition berechnen (oben)
        zielPosition = startPosition + Vector3.up * distance;

        // Zufällige Startwartezeit, damit nicht alle Würmer gleichzeitig starten
        timer = Random.Range(0f, maxWarteZeitUnten);
    }

    void Update()
    {
        // Treffer-Animation: sofort nach unten
        if (isHit)
        {
            transform.localPosition = Vector3.MoveTowards(transform.localPosition, startPosition, hitSpeed * Time.deltaTime);
            if (Vector3.Distance(transform.localPosition, startPosition) < 0.01f)
            {
                transform.localPosition = startPosition;
                isHit = false;
                isUp = false;
                isMoving = false;
                // Wartezeit nach Treffer
                timer = Random.Range(minWarteZeitUnten, maxWarteZeitUnten);
            }
            return; // Normale Bewegung während Treffer ignorieren
        }

        if (isMoving)
        {
            // Wurm bewegt sich
            if (isUp)
            {
                // Nach unten bewegen
                transform.localPosition = Vector3.MoveTowards(transform.localPosition, startPosition, speed * Time.deltaTime);

                // Wenn unten angekommen
                if (Vector3.Distance(transform.localPosition, startPosition) < 0.01f)
                {
                    transform.localPosition = startPosition;
                    isUp = false;
                    isMoving = false;
                    // Neue zufällige Wartezeit unten
                    timer = Random.Range(minWarteZeitUnten, maxWarteZeitUnten);
                }
            }
            else
            {
                // Nach oben bewegen
                transform.localPosition = Vector3.MoveTowards(transform.localPosition, zielPosition, speed * Time.deltaTime);

                // Wenn oben angekommen
                if (Vector3.Distance(transform.localPosition, zielPosition) < 0.01f)
                {
                    transform.localPosition = zielPosition;
                    isUp = true;
                    isMoving = false;
                    // Neue zufällige Wartezeit oben
                    timer = Random.Range(minWarteZeitOben, maxWarteZeitOben);
                }
            }
        }
        else
        {
            // Wurm wartet
            timer -= Time.deltaTime;
            if (timer <= 0) isMoving = true;
        }
    }

    /// <summary>
    /// Wird aufgerufen wenn der Hammer den Wurm berührt (Trigger-Collider).
    /// </summary>
    void OnTriggerEnter(Collider other)
    {
        // Nur treffen wenn der Wurm oben ist und noch nicht getroffen wurde
        if (!isHit && isUp && other.CompareTag(hammerTag))
        {
            isHit = true;
            isMoving = false;
            // Punkt vergeben
            if (ScoreManager.Instance != null)
                ScoreManager.Instance.WurmGetroffen();
        }
    }
}

using UnityEngine;

/// <summary>
/// Spawnt 9 Würmer in einem 3x3-Raster (Whack-a-Mole Layout)
/// und weist jedem das MoleMovement-Script zu.
/// </summary>
public class MoleSpawner : MonoBehaviour
{
    [Header("Prefab")]
    [Tooltip("Das Wurm-Prefab (muss MoleMovement-Script haben oder es wird automatisch hinzugefügt)")]
    [SerializeField] private GameObject molePrefab;

    [Header("Raster Einstellungen")]
    [SerializeField] private int columns = 3;           // Spalten
    [SerializeField] private int rows = 3;              // Reihen
    [SerializeField] private float spacingX = 0.5f;    // Abstand in X-Richtung
    [SerializeField] private float spacingZ = 0.5f;    // Abstand in Z-Richtung
    [SerializeField] private float spawnOffsetY = 0f;  // Y-Versatz (negativ = tiefer)

    [Header("Bewegungseinstellungen (für alle Würmer)")]
    [SerializeField] private float moveDistance = 0.3f;     // Wie weit der Wurm hochkommt
    [SerializeField] private float moveSpeed = 1.5f;        // Bewegungsgeschwindigkeit
    [SerializeField] private float minWaitDown = 1f;        // Min. Wartezeit unten
    [SerializeField] private float maxWaitDown = 3f;        // Max. Wartezeit unten
    [SerializeField] private float minWaitUp = 0.5f;        // Min. Wartezeit oben
    [SerializeField] private float maxWaitUp = 2f;          // Max. Wartezeit oben

    void Start()
    {
        if (molePrefab == null)
        {
            Debug.LogError("MoleSpawner: Kein Prefab zugewiesen! Bitte molePrefab im Inspector setzen.");
            return;
        }

        SpawnMoles();
    }

    void SpawnMoles()
    {
        // Mittelpunkt des Rasters berechnen, damit es zentriert spawnt
        float totalWidth  = (columns - 1) * spacingX;
        float totalDepth  = (rows - 1) * spacingZ;
        Vector3 offset = new Vector3(-totalWidth / 2f, 0f, -totalDepth / 2f);

        for (int row = 0; row < rows; row++)
        {
            for (int col = 0; col < columns; col++)
            {
                // Position im Raster
                Vector3 localPos = offset + new Vector3(col * spacingX, 0f, row * spacingZ);
                Vector3 worldPos = transform.position + transform.TransformDirection(localPos);

                // Wurm instantiieren mit X-Rotation -180 (damit er richtig ausgerichtet ist)
                Quaternion spawnRotation = Quaternion.Euler(-180f, 0f, 0f);
                GameObject mole = Instantiate(molePrefab, worldPos, spawnRotation, transform);
                mole.name = $"Mole_{row * columns + col + 1}";

                // MoleMovement-Script holen oder hinzufügen
                MoleMovement movement = mole.GetComponent<MoleMovement>();
                if (movement == null)
                    movement = mole.AddComponent<MoleMovement>();

                // Einstellungen per Reflection übernehmen (einfacher: public Methode)
                movement.SetSettings(moveDistance, moveSpeed, minWaitDown, maxWaitDown, minWaitUp, maxWaitUp);
            }
        }

        Debug.Log($"MoleSpawner: {columns * rows} Würmer gespawnt.");
    }
}

